function simulateChildrenAsProps() {
  let childrenRenderCount = 0;
  let timerRenderCount = 0;

  // Children are created once by the parent (stable reference)
  function createChildren() {
    childrenRenderCount++;
    return 'ExpensiveContent (rendered ' + childrenRenderCount + ' time(s))';
  }

  // Create children once (simulating parent creating JSX)
  const children = createChildren();

  // Timer wrapper re-renders on every tick
  function timerTick(tick) {
    timerRenderCount++;
    console.log('Timer tick: ' + tick + ' | Timer renders: ' + timerRenderCount + ' | Children: ' + children);
  }

  console.log('Children created once: ' + children);
  timerTick(1);
  timerTick(2);
  timerTick(3);
  console.log('Children render count: ' + childrenRenderCount);
  console.log('Timer render count: ' + timerRenderCount);
}

