function createModuleSystem() {
  const registry = {};
  const loaded = {};

  return {
    register: (name, factory) => {
      registry[name] = factory;
    },
    lazyLoad: (name) => {
      if (loaded[name]) {
        console.log('[' + name + '] Already loaded (cached)');
        return loaded[name];
      }
      if (!registry[name]) {
        console.log('[' + name + '] Module not found!');
        return null;
      }
      console.log('[' + name + '] Loading module...');
      loaded[name] = registry[name]();
      console.log('[' + name + '] Loaded successfully');
      return loaded[name];
    },
    getLoadedCount: () => Object.keys(loaded).length
  };
}

const modules = createModuleSystem();
