function virtualRender(items, viewportHeight, itemHeight, scrollTop, overscan) {
  const visibleCount = Math.ceil(viewportHeight / itemHeight);
  const rawStart = Math.floor(scrollTop / itemHeight);
  const rawEnd = rawStart + visibleCount - 1;

  // Apply overscan
  const startIndex = Math.max(0, rawStart - overscan);
  const endIndex = Math.min(items.length - 1, rawEnd + overscan);
  const renderedCount = endIndex - startIndex + 1;

  console.log('Scroll: ' + scrollTop + 'px | Window: [' + startIndex + '-' + endIndex + '] | Rendered: ' + renderedCount + '/' + items.length);

  for (let i = startIndex; i <= endIndex; i++) {
    const isOverscan = i < rawStart || i > rawEnd;
    console.log('  ' + (isOverscan ? '(buffer) ' : '') + items[i]);
  }
}

const items = Array.from({ length: 1000 }, (_, i) => 'Item ' + (i + 1));

